+    let repair_symbols_needed = dropped_source_symbols + decoder.params().s + decoder.params().h;
+    let mut received = decoder.constraint_symbols();
+    for (index, symbol) in source_symbols
+        .iter()
+        .enumerate()
+        .skip(dropped_source_symbols)
